using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class WebSearchTool
{
    private static readonly HttpClient s_httpClient = new();

    [Description("Searches the web for information on a given query. Returns a list of relevant snippets and URLs.")]
    public static async Task<string> SearchWeb(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return (1-5)")] int maxResults = 3)
    {
        maxResults = Math.Clamp(maxResults, 1, 5);

        try
        {
            // Use a public search API (DuckDuckGo Instant Answer API as a lightweight option)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var response = await s_httpClient.GetFromJsonAsync<JsonElement>(url);
            var results = new List<string>();

            // Extract abstract if available
            var abstractText = response.GetProperty("AbstractText").GetString();
            var abstractUrl = response.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[Summary] {abstractText}\nSource: {abstractUrl}");
            }

            // Extract related topics
            if (response.TryGetProperty("RelatedTopics", out var topics) && topics.ValueKind == JsonValueKind.Array)
            {
                foreach (var topic in topics.EnumerateArray().Take(maxResults))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        topic.TryGetProperty("FirstURL", out var topicUrl))
                    {
                        var snippet = text.GetString();
                        var link = topicUrl.GetString();
                        if (!string.IsNullOrWhiteSpace(snippet))
                        {
                            results.Add($"[Result] {snippet}\nURL: {link}");
                        }
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No results found for '{query}'. Try rephrasing the search query.";
            }

            return string.Join("\n\n", results.Take(maxResults));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class NoteTakingTool
{
    private readonly List<(string Category, string Content)> _notes = [];

    [Description("Saves a research note under a given category. Use this to record key findings during research.")]
    public string AddNote(
        [Description("The category for the note (e.g., 'definition', 'key_fact', 'example', 'source')")] string category,
        [Description("The content of the note to save")] string content)
    {
        _notes.Add((category, content));
        return $"Note saved under '{category}'. Total notes: {_notes.Count}";
    }

    [Description("Retrieves all saved research notes, optionally filtered by category.")]
    public string GetNotes(
        [Description("Optional category to filter notes by. Leave empty to get all notes.")] string? category = null)
    {
        var filtered = string.IsNullOrWhiteSpace(category)
            ? _notes
            : _notes.Where(n => n.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

        if (filtered.Count == 0)
        {
            return category is null
                ? "No notes have been saved yet."
                : $"No notes found under category '{category}'.";
        }

        var grouped = filtered
            .GroupBy(n => n.Category, StringComparer.OrdinalIgnoreCase)
            .Select(g => $"## {g.Key}\n" + string.Join("\n", g.Select((n, i) => $"  {i + 1}. {n.Content}")));

        return string.Join("\n\n", grouped);
    }
}

