using Microsoft.Extensions.AI;
using Microsoft.Agents.AI.ChatCompletion;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient ---
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Register tools ---
var noteTaker = new NoteTakingTool();

IList<AITool> tools =
[
    AIFunctionFactory.Create(WebSearchTool.SearchWeb),
    AIFunctionFactory.Create(noteTaker.AddNote),
    AIFunctionFactory.Create(noteTaker.GetNotes),
];

// --- Create the agent ---
var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Instructions = """
        You are a research agent. Your job is to thoroughly research a topic provided by the user.

        Follow this process:
        1. Search the web for information on the topic (use multiple searches with different queries)
